const q = $json.query || {};
const b = $json.body  || {};
const url = q.url || b.url || '';
if (!url) {
  // Return a Discord error rather than failing silently
  return [{ json: { error: true, url: '', message: 'No url parameter provided. Use ?url=JOB_URL' } }];
}
return [{ json: { url, error: false } }];

const resp   = $input.first().json;
const urlRef = $('Extract URL').first().json.url;

let result = {};
const raw  = resp.content?.[0]?.text || '';

try {
  const cleaned = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
  result = JSON.parse(cleaned);
} catch(e) {
  result = {
    job: { title: 'Unknown', company: 'Unknown', location: '', salary: '', is_remote: false, role_type: 'Other', tags: [] },
    resume_sections: null,
    cover_letter: raw || 'Generation failed.'
  };
}

const job = result.job || {};
const s   = result.resume_sections;

function slugify(str, max) {
  return (str || '').replace(/[^\w\s-]/g,'').replace(/\s+/g,' ').trim().substring(0, max || 60);
}

const docDate     = new Date().toISOString().split('T')[0];
const folderName  = slugify(`${job.company} - ${job.title}`, 80);
const resumeTitle = `Resume - ${slugify(job.title,45)} - ${(job.company||'').substring(0,25)} ${docDate}`;
const clTitle     = `Cover Letter - ${slugify(job.title,40)} - ${(job.company||'').substring(0,25)} ${docDate}`;

let resumeText = '';
if (s) {
  const expSection = (s.experience || []).map(exp => {
    const bullets = (exp.bullets || []).map(b => '    \u2022 ' + b).join('\n');
    const roleInfo = [exp.title, exp.dates].filter(Boolean).join('  |  ');
    return `${(exp.company||'').toUpperCase()}\n${roleInfo}\n${bullets}`;
  }).join('\n\n');

  resumeText = [
    'GADGET',
    'Walla Walla, WA  \u2022  505.926.1010  \u2022  your.email@example.com  \u2022  https://www.gadget.com',
    '',
    `Tailored for: ${job.title} at ${job.company}`,
    '',
    '------------------------------------------------------------',
    'PROFESSIONAL SUMMARY',
    '------------------------------------------------------------',
    s.summary || '',
    '',
    '------------------------------------------------------------',
    'CORE COMPETENCIES',
    '------------------------------------------------------------',
    (s.core_competencies || []).join('  \u2022  '),
    '',
    '------------------------------------------------------------',
    'PROFESSIONAL EXPERIENCE',
    '------------------------------------------------------------',
    expSection,
    '',
    '------------------------------------------------------------',
    'TECHNICAL SKILLS',
    '------------------------------------------------------------',
    s.technical_skills || '',
    '',
    '------------------------------------------------------------',
    'EDUCATION',
    '------------------------------------------------------------',
    s.education || '',
  ].join('\n');
} else {
  resumeText = 'Resume generation failed. Raw Claude output:\n' + raw.substring(0, 2000);
}

const coverLetterText = [
  `${job.company}`,
  `Re: ${job.title}`,
  `Date: ${new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}`,
  '',
  result.cover_letter || 'Cover letter generation failed.',
  '',
  'Sincerely,',
  'Gadget',
  'your.email@example.com  |  505.926.1010',
  'https://www.gadget.com',
].join('\n');

// Pre-build batchUpdate bodies so HTTP nodes don't need complex inline expressions
const resumeBatchBody = JSON.stringify({
  requests: [{ insertText: { location: { index: 1 }, text: resumeText } }]
});
const clBatchBody = JSON.stringify({
  requests: [{ insertText: { location: { index: 1 }, text: coverLetterText } }]
});

return [{ json: {
  job, url: urlRef,
  resume_text: resumeText, cover_letter_text: coverLetterText,
  resume_batch_body: resumeBatchBody, cl_batch_body: clBatchBody,
  folder_name: folderName, resume_title: resumeTitle, cl_title: clTitle,
}}];

const d       = $('Parse Apply Docs').first().json;
const resume  = $('Create Resume Doc').first().json;
const cl      = $('Create Cover Letter Doc').first().json;
const folder  = $('Create App Folder').first().json;
const job     = d.job;

const folderId  = folder.id;
const folderUrl = 'https://drive.google.com/drive/folders/' + folderId;
const resumeUrl = 'https://docs.google.com/document/d/' + resume.documentId + '/edit';
const clUrl     = 'https://docs.google.com/document/d/' + cl.documentId + '/edit';
const today     = new Date().toISOString().split('T')[0];

function para(text) {
  return {object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:(text||'').substring(0,2000)}}]}};
}
function h2(text) {
  return {object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:text}}]}};
}

const children = [
  h2('\uD83D\uDCC1 Application Documents'),
  para('\uD83D\uDCC1 Drive Folder: ' + folderUrl),
  para('\uD83D\uDCDD Resume: ' + resumeUrl),
  para('\u2709\uFE0F Cover Letter: ' + clUrl),
  {object:'block',type:'divider',divider:{}},
  h2('\uD83D\uDD17 Source'),
  para('Manually added via apply-url webhook'),
  para('URL: ' + (d.url || '')),
];

const body = {
  parent: { database_id: "YOUR_NOTION_DATABASE_ID" },
  properties: {
    "Job Title":   { title:      [{ text: { content: (job.title   ||'Unknown').substring(0,200) } }] },
    "Company":     { rich_text:  [{ text: { content: (job.company ||'Unknown').substring(0,200) } }] },
    "Source":      { select:     { name: 'Manual' } },
    "Apply URL":   { url: d.url || null },
    "Location":    { rich_text:  [{ text: { content: (job.location||'').substring(0,200) } }] },
    "Score":       { number: 0 },
    "Role Type":   { select:     { name: job.role_type || 'Other' } },
    "Priority":    { select:     { name: 'High' } },
    "Tags":        { multi_select: (job.tags||[]).map(t => ({name: String(t).substring(0,100)})) },
    "Status":      { select:     { name: 'Docs Ready' } },
    "Drive Folder":{ url: folderUrl },
    "Date Found":  { date:       { start: today } },
  },
  children,
};

const salaryLine = job.salary ? '\n\uD83D\uDCB0 ' + job.salary : '';
const locLine    = job.location ? '\n\uD83D\uDCCD ' + job.location + (job.is_remote ? ' (Remote)' : '') : '';

const discordMsg = [
  '\uD83D\uDCC4 **Application docs ready!** (Manual add)',
  '**' + (job.title||'?') + '** @ ' + (job.company||'?'),
  job.salary   ? '\uD83D\uDCB0 ' + job.salary   : '',
  job.location ? '\uD83D\uDCCD ' + job.location + (job.is_remote ? ' (Remote)' : '') : '',
  '',
  '\uD83D\uDCC1 [Application Folder](' + folderUrl + ')',
  '\uD83D\uDCDD [Tailored Resume](' + resumeUrl + ')',
  '\u2709\uFE0F [Cover Letter](' + clUrl + ')',
  '',
  'Apply: ' + (d.url || ''),
].filter(Boolean).join('\n');

return [{ json: { notion_body: JSON.stringify(body), discord_msg: discordMsg } }];
